CustomField.formula:
IF(
  AND (
    NOT ISBLANK(BillingCountry),
    NOT ISBLANK(BillingCity) 
  ), UPPER(BillingCountry) + ', ' + BillingCity,
    IF(
      AND (
        NOT ISBLANK(BillingCountry),
        ISBLANK(BillingCity) 
      ), UPPER(BillingCountry),
      IF(
        AND (
          ISBLANK(BillingCountry),
          NOT ISBLANK(BillingCity) 
        ), BillingCity, ''
	  )
	)
)
